# FizzBuzz
for i in range(1, 51):
    if i % 15 == 0: print('FizzBuzz')
    elif i % 3 == 0: print('Fizz')
    elif i % 5 == 0: print('Buzz')
    else: print(i)

# Sum evens 1-100
total = 0
for n in range(2, 101, 2):
    total += n
print('Sum of evens:', total)  # 2550
